const { app } = require('@azure/functions');

// =============================================================================
// DEV-ONLY CONFIGURATION — REPLACE WITH KEY VAULT REFERENCES BEFORE PRODUCTION
// =============================================================================
// Production pattern (in Application Settings):
//   SENDGRID_API_KEY = @Microsoft.KeyVault(SecretUri=https://<vault>.vault.azure.net/secrets/SendGridApiKey/)
//   TWILIO_ACCOUNT_SID = @Microsoft.KeyVault(SecretUri=https://<vault>.vault.azure.net/secrets/TwilioAccountSid/)
//   TWILIO_AUTH_TOKEN = @Microsoft.KeyVault(SecretUri=https://<vault>.vault.azure.net/secrets/TwilioAuthToken/)
// =============================================================================

const DEV_CONFIG = {
    SENDGRID_API_KEY: 'SG.azure_demo_key_123',
    TWILIO_ACCOUNT_SID: 'AC1234567890abcdef',
    TWILIO_AUTH_TOKEN: 'dev_twilio_auth_token_placeholder',
    TWILIO_FROM_PHONE: '+15551234567',
    SENDGRID_FROM_EMAIL: 'noreply@example.com',
    SENDGRID_FROM_NAME: 'Azure Function Dev'
};

function getConfig(key) {
    // Prefer environment variables (App Settings / Key Vault refs) over hardcoded values
    return process.env[key] || DEV_CONFIG[key];
}

function isProduction() {
    const env = (process.env.NODE_ENV || process.env.AZURE_FUNCTIONS_ENVIRONMENT || '').toLowerCase();
    return env === 'production';
}

function validateProductionSecrets(context) {
    if (isProduction()) {
        const hardcodedKeys = Object.keys(DEV_CONFIG);
        const missingFromEnv = hardcodedKeys.filter(k => !process.env[k]);
        if (missingFromEnv.length > 0) {
            const errorMsg = `PRODUCTION SECURITY ERROR: The following secrets are not set in environment/Key Vault and would fall back to hardcoded dev values: ${missingFromEnv.join(', ')}. Aborting.`;
            context.error(errorMsg);
            throw new Error(errorMsg);
        }
    }
}

// --- SendGrid Email Service ---
async function sendEmail({ to, subject, textContent, htmlContent }, context) {
    const apiKey = getConfig('SENDGRID_API_KEY');
    const fromEmail = getConfig('SENDGRID_FROM_EMAIL');
    const fromName = getConfig('SENDGRID_FROM_NAME');

    const payload = {
        personalizations: [
            {
                to: Array.isArray(to) ? to.map(email => ({ email })) : [{ email: to }],
                subject: subject
            }
        ],
        from: {
            email: fromEmail,
            name: fromName
        },
        content: []
    };

    if (textContent) {
        payload.content.push({ type: 'text/plain', value: textContent });
    }
    if (htmlContent) {
        payload.content.push({ type: 'text/html', value: htmlContent });
    }
    if (payload.content.length === 0) {
        payload.content.push({ type: 'text/plain', value: '' });
    }

    context.log(`Sending email via SendGrid to: ${JSON.stringify(to)}, subject: "${subject}"`);

    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
        method: 'POST',
        headers: {
            'Authorization': `Bearer ${apiKey}`,
            'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
    });

    if (!response.ok) {
        const errorBody = await response.text();
        throw new Error(`SendGrid API error (${response.status}): ${errorBody}`);
    }

    context.log(`Email sent successfully. Status: ${response.status}`);
    return {
        success: true,
        statusCode: response.status,
        messageId: response.headers.get('x-message-id') || null
    };
}

// --- Twilio SMS Service ---
async function sendSms({ to, body }, context) {
    const accountSid = getConfig('TWILIO_ACCOUNT_SID');
    const authToken = getConfig('TWILIO_AUTH_TOKEN');
    const fromPhone = getConfig('TWILIO_FROM_PHONE');

    const twilioUrl = `https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`;

    const params = new URLSearchParams();
    params.append('To', to);
    params.append('From', fromPhone);
    params.append('Body', body);

    const authHeader = 'Basic ' + Buffer.from(`${accountSid}:${authToken}`).toString('base64');

    context.log(`Sending SMS via Twilio to: ${to}`);

    const response = await fetch(twilioUrl, {
        method: 'POST',
        headers: {
            'Authorization': authHeader,
            'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: params.toString()
    });

    const responseBody = await response.json();

    if (!response.ok) {
        throw new Error(`Twilio API error (${response.status}): ${responseBody.message || JSON.stringify(responseBody)}`);
    }

    context.log(`SMS sent successfully. SID: ${responseBody.sid}`);
    return {
        success: true,
        statusCode: response.status,
        messageSid: responseBody.sid,
        status: responseBody.status
    };
}

// --- Input Validation ---
function validateEmailInput(data) {
    const errors = [];
    if (!data.to) errors.push('Email "to" field is required');
    if (!data.subject) errors.push('Email "subject" field is required');
    if (!data.textContent && !data.htmlContent) {
        errors.push('Either "textContent" or "htmlContent" is required for email');
    }
    return errors;
}

function validateSmsInput(data) {
    const errors = [];
    if (!data.to) errors.push('SMS "to" phone number is required');
    if (!data.body) errors.push('SMS "body" is required');
    if (data.to && !/^\+[1-9]\d{1,14}$/.test(data.to)) {
        errors.push('SMS "to" must be in E.164 format (e.g., +15551234567)');
    }
    return errors;
}

// --- Main Function: Send Notification ---
app.http('sendNotification', {
    methods: ['POST'],
    authLevel: 'function',
    route: 'notify',
    handler: async (request, context) => {
        context.log('sendNotification function triggered');

        try {
            // Block hardcoded secrets in production
            validateProductionSecrets(context);

            const requestBody = await request.json();
            const { channel, email, sms } = requestBody;

            if (!channel) {
                return {
                    status: 400,
                    jsonBody: {
                        error: 'Missing "channel" field. Must be "email", "sms", or "both".'
                    }
                };
            }

            const results = {};
            const errors = [];

            // Send email
            if (channel === 'email' || channel === 'both') {
                if (!email) {
                    errors.push('Email channel requested but "email" object is missing from request body');
                } else {
                    const emailErrors = validateEmailInput(email);
                    if (emailErrors.length > 0) {
                        errors.push(...emailErrors);
                    } else {
                        try {
                            results.email = await sendEmail(email, context);
                        } catch (err) {
                            context.error(`Email send failed: ${err.message}`);
                            results.email = { success: false, error: err.message };
                        }
                    }
                }
            }

            // Send SMS
            if (channel === 'sms' || channel === 'both') {
                if (!sms) {
                    errors.push('SMS channel requested but "sms" object is missing from request body');
                } else {
                    const smsErrors = validateSmsInput(sms);
                    if (smsErrors.length > 0) {
                        errors.push(...smsErrors);
                    } else {
                        try {
                            results.sms = await sendSms(sms, context);
                        } catch (err) {
                            context.error(`SMS send failed: ${err.message}`);
                            results.sms = { success: false, error: err.message };
                        }
                    }
                }
            }

            if (!['email', 'sms', 'both'].includes(channel)) {
                return {
                    status: 400,
                    jsonBody: {
                        error: `Invalid channel "${channel}". Must be "email", "sms", or "both".`
                    }
                };
            }

            if (errors.length > 0) {
                return {
                    status: 400,
                    jsonBody: {
                        error: 'Validation failed',
                        details: errors,
                        results
                    }
                };
            }

            const overallSuccess = Object.values(results).every(r => r.success);

            return {
                status: overallSuccess ? 200 : 207,
                jsonBody: {
                    success: overallSuccess,
                    channel,
                    results,
                    environment: isProduction() ? 'production' : 'development',
                    timestamp: new Date().toISOString()
                }
            };

        } catch (err) {
            context.error(`Unhandled error in sendNotification: ${err.message}`);
            return {
                status: 500,
                jsonBody: {
                    error: 'Internal server error',
                    message: isProduction() ? 'An unexpected error occurred' : err.message
                }
            };
        }
    }
});

